import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { useNavigate } from 'react-router-dom';
import { FaPlus } from 'react-icons/fa';
import { Header } from '../../components/Header';
import { Card } from '../../components/Card';
import { Button } from '../../components/Button';
import { useAuth } from '../../contexts/AuthContext';
import { api } from '../../services/api';

const Container = styled.div`
  min-height: 100vh;
  background-color: ${props => props.theme.colors.background};
`;

const Content = styled.main`
  max-width: 1200px;
  margin: 0 auto;
  padding: ${props => props.theme.spacing.xl};
`;

const AddViagemSection = styled.section`
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-bottom: ${props => props.theme.spacing.xxl};
`;

const AddCard = styled(Card)`
  width: 200px;
  height: 200px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    transform: scale(1.05);
    background-color: ${props => props.theme.colors.primary}10;
  }
`;

const PlusIcon = styled(FaPlus)`
  font-size: 4rem;
  color: ${props => props.theme.colors.primary};
`;

const AddText = styled.p`
  margin-top: ${props => props.theme.spacing.md};
  font-size: ${props => props.theme.fontSizes.large};
  color: ${props => props.theme.colors.darkGray};
  font-weight: 500;
`;

const Divider = styled.hr`
  border: none;
  border-top: 2px solid ${props => props.theme.colors.primary}40;
  margin: ${props => props.theme.spacing.xl} 0;
`;

const ViagensAnteriores = styled.section`
  h2 {
    color: ${props => props.theme.colors.primary};
    margin-bottom: ${props => props.theme.spacing.lg};
    font-size: ${props => props.theme.fontSizes.xlarge};
  }
`;

const ViagensGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: ${props => props.theme.spacing.lg};
`;

const ViagemCard = styled(Card)`
  display: flex;
  flex-direction: column;
  gap: ${props => props.theme.spacing.sm};
`;

const ViagemData = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: ${props => props.theme.fontSizes.medium};
`;

const ViagemLocal = styled.div`
  color: ${props => props.theme.colors.primary};
  font-weight: 600;
  margin: ${props => props.theme.spacing.xs} 0;
`;

const ViagemPeriodo = styled.div`
  color: ${props => props.theme.colors.darkGray};
  font-size: ${props => props.theme.fontSizes.small};
`;

// Dados simulados para teste
const viagensSimuladas = [
  {
    id: 1,
    cidade_saida: 'São Paulo',
    cidade_chegada: 'Rio de Janeiro',
    data_entrada: '2024-03-15',
    data_chegada: '2024-03-17',
    km_saida: 1000,
    km_entrada: 1500,
    peso_saida: 20
  },
  {
    id: 2,
    cidade_saida: 'Curitiba',
    cidade_chegada: 'Porto Alegre',
    data_entrada: '2024-03-10',
    data_chegada: '2024-03-12',
    km_saida: 2000,
    km_entrada: 2450,
    peso_saida: 18
  },
  {
    id: 3,
    cidade_saida: 'Belo Horizonte',
    cidade_chegada: 'Brasília',
    data_entrada: '2024-03-05',
    data_chegada: '2024-03-07',
    km_saida: 3000,
    km_entrada: 3450,
    peso_saida: 22
  }
];

export const Home = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [viagens, setViagens] = useState([]);
  const [loading, setLoading] = useState(true);
  const [usandoSimulacao, setUsandoSimulacao] = useState(false);

  useEffect(() => {
    carregarViagens();
  }, []);

  const carregarViagens = async () => {
    try {
      // Tenta carregar do backend
      const response = await api.get('/viagens');
      setViagens(response.data);
      setUsandoSimulacao(false);
    } catch (error) {
      console.log('Usando dados simulados (backend não disponível)');
      // Se o backend não estiver disponível, usa dados simulados
      setViagens(viagensSimuladas);
      setUsandoSimulacao(true);
    } finally {
      setLoading(false);
    }
  };

  const formatarData = (data) => {
    return new Date(data).toLocaleDateString('pt-BR');
  };

  return (
    <Container>
      <Header />
      
      <Content>
        <AddViagemSection>
          <AddCard onClick={() => navigate('/nova-viagem')}>
            <PlusIcon />
          </AddCard>
          <AddText>Adicionar Nova Viagem</AddText>
        </AddViagemSection>

        {usandoSimulacao && (
          <div style={{ 
            backgroundColor: '#FFE4B5', 
            padding: '10px', 
            borderRadius: '8px', 
            marginBottom: '20px',
            textAlign: 'center',
            color: '#9A6767'
          }}>
            ⚠️ Modo de demonstração - Dados simulados (backend não conectado)
          </div>
        )}

        <Divider />

        <ViagensAnteriores>
          <h2>Viagens Anteriores</h2>
          
          {loading ? (
            <p>Carregando...</p>
          ) : viagens.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
              <p>Nenhuma viagem encontrada</p>
              <p style={{ fontSize: '14px', marginTop: '10px' }}>
                Clique no botão "+" para adicionar sua primeira viagem
              </p>
            </div>
          ) : (
            <ViagensGrid>
              {viagens.map(viagem => (
                <ViagemCard 
                  key={viagem.id}
                  onClick={() => navigate(`/viagem/${viagem.id}`)}
                >
                  <ViagemLocal>
                    {viagem.cidade_saida} → {viagem.cidade_chegada}
                  </ViagemLocal>
                  
                  <ViagemPeriodo>
                    {formatarData(viagem.data_entrada)} - {formatarData(viagem.data_chegada)}
                  </ViagemPeriodo>
                  
                  <ViagemData>
                    <span>KM: {viagem.km_saida} - {viagem.km_entrada}</span>
                    <span>Peso: {viagem.peso_saida}t</span>
                  </ViagemData>
                </ViagemCard>
              ))}
            </ViagensGrid>
          )}
        </ViagensAnteriores>
      </Content>
    </Container>
  );
};
